const sharp = require('sharp');
const path = require('path');
const src = './attached_assets/Screenshot_2026-05-25_at_4.08.52_PM_1780285826936.png';
const out = './client/public';

const sizes = [
  { name: 'favicon-16.png',           size: 16  },
  { name: 'favicon-32.png',           size: 32  },
  { name: 'favicon-48.png',           size: 48  },
  { name: 'icon-70.png',              size: 70  },
  { name: 'apple-touch-icon-120.png', size: 120 },
  { name: 'icon-144.png',             size: 144 },
  { name: 'apple-touch-icon-152.png', size: 152 },
  { name: 'apple-touch-icon-180.png', size: 180 },
  { name: 'icon-150.png',             size: 150 },
  { name: 'icon-192.png',             size: 192 },
  { name: 'icon-192-maskable.png',    size: 192 },
  { name: 'icon-256.png',             size: 256 },
  { name: 'icon-310.png',             size: 310 },
  { name: 'icon-512.png',             size: 512 },
  { name: 'icon-512-maskable.png',    size: 512 },
  { name: 'icon-48.png',              size: 48  },
  { name: 'icon-32.png',              size: 32  },
  { name: 'icon-96.png',              size: 96  },
  { name: 'icon-180.png',             size: 180 },
];

async function gen() {
  const img = sharp(src).png({ quality: 100, compressionLevel: 0 });
  const meta = await sharp(src).metadata();
  for (const s of sizes) {
    await sharp(src)
      .resize(s.size, s.size, { fit: 'cover', position: 'centre' })
      .png({ quality: 100, compressionLevel: 0 })
      .toFile(path.join(out, s.name));
    process.stdout.write('.');
  }
  // icon-310x150 wide tile
  await sharp(src)
    .resize(310, 150, { fit: 'contain', background: { r:0, g:0, b:0, alpha:1 } })
    .png({ quality: 100, compressionLevel: 0 })
    .toFile(path.join(out, 'icon-310x150.png'));
  console.log('\nDone!');
}
gen().catch(e => { console.error(e); process.exit(1); });
