     5→const BIOMETRIC_DEVICE_KEY = "qirox_biometric_device";
     6→
     7→export function isBiometricSupported(): boolean {
     8→  return (
     9→    typeof window !== "undefined" &&
    10→    !!window.PublicKeyCredential &&
    11→    typeof window.PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable === "function"
    12→  );
    13→}
    14→
    15→export async function checkBiometricAvailable(): Promise<boolean> {
    16→  if (!isBiometricSupported()) return false;
    17→  try {
    18→    return await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
    19→  } catch {
    20→    return false;
    21→  }
    22→}
    23→
    24→/** Mark that a biometric has been registered on this device */
    25→export function markBiometricRegistered(): void {
    26→  try { localStorage.setItem(BIOMETRIC_DEVICE_KEY, "1"); } catch {}
    27→}
    28→
    29→/** Check if any biometric was previously registered from this browser */
    30→export function isBiometricRegisteredLocally(): boolean {
    31→  try { return localStorage.getItem(BIOMETRIC_DEVICE_KEY) === "1"; } catch { return false; }
    32→}
    33→
    34→/** Clear local biometric flag (e.g. after deleting all credentials) */
    35→export function clearBiometricLocal(): void {
    36→  try { localStorage.removeItem(BIOMETRIC_DEVICE_KEY); } catch {}
    37→}
