    39→async function apiFetch(url: string, body?: object) {
    40→  const res = await fetch(url, {
    41→    method: body !== undefined ? "POST" : "GET",
    42→    credentials: "include",
    43→    headers: { "Content-Type": "application/json" },
    44→    ...(body !== undefined ? { body: JSON.stringify(body) } : {}),
    45→  });
    46→  const data = await res.json().catch(() => ({}));
    47→  if (!res.ok) throw new Error(data.error || `خطأ ${res.status}`);
    48→  return data;
    49→}
    50→
    51→export async function registerBiometric(deviceName?: string): Promise<void> {
    52→  const options = await apiFetch("/api/auth/webauthn/register-options", {});
    53→  const attestation = await startRegistration({ optionsJSON: options });
    54→  await apiFetch("/api/auth/webauthn/register-verify", {
    55→    response: attestation,
    56→    deviceName: deviceName || getDeviceLabel(),
    57→  });
    58→  markBiometricRegistered();
    59→  await queryClient.invalidateQueries({ queryKey: ["/api/auth/webauthn/credentials"] });
    60→}
    61→
    62→/**
    63→ * Login with biometric.
    64→ * - If identifier provided: targeted flow (server returns only user's credentials)
    65→ * - If no identifier: discoverable/resident-key flow (browser shows its own picker)
    66→ */
    67→export async function loginWithBiometric(identifier?: string): Promise<any> {
    68→  const body: Record<string, string> = {};
    69→  if (identifier?.trim()) body.identifier = identifier.trim();
    70→
    71→  const options = await apiFetch("/api/auth/webauthn/auth-options", body);
    72→  const assertion = await startAuthentication({ optionsJSON: options });
    73→  const user = await apiFetch("/api/auth/webauthn/auth-verify", { response: assertion });
    74→  if (user.deviceToken) {
    75→    saveDeviceToken(user.deviceToken);
    76→  }
    77→  markBiometricRegistered();
    78→  const userData = { ...user };
    79→  delete userData.deviceToken;
    80→  queryClient.setQueryData(["/api/user"], userData);
    81→  return userData;
    82→}
