    84→function getDeviceLabel(): string {
    85→  const ua = navigator.userAgent;
    86→  if (/iPhone/.test(ua)) return "iPhone";
    87→  if (/iPad/.test(ua)) return "iPad";
    88→  if (/Android/.test(ua)) return "Android";
    89→  if (/Mac/.test(ua)) return "Mac";
    90→  if (/Windows/.test(ua)) return "Windows";
    91→  return "جهاز محفوظ";
    92→}
